FUNCTION AnalogScale : REAL
VAR_INPUT
    RawValue : INT;
    RawMin   : INT;
    RawMax   : INT;
    EngMin   : REAL;
    EngMax   : REAL;
END_VAR
VAR
    tmp : REAL;
END_VAR
BEGIN
    IF RawValue <= RawMin THEN
        AnalogScale := EngMin;
    ELSIF RawValue >= RawMax THEN
        AnalogScale := EngMax;
    ELSE
        tmp := (REAL(RawValue) - REAL(RawMin)) / (REAL(RawMax) - REAL(RawMin)) * (EngMax - EngMin);
        AnalogScale := EngMin + tmp;
    END_IF;
END_FUNCTION

PROGRAM TankLevelMonitor
VAR_INPUT
    RawLevel     : INT;
    HighAlarmSP  : REAL := 85.0;
    LowAlarmSP   : REAL := 15.0;
    Hysteresis   : REAL := 2.0;
END_VAR
VAR_OUTPUT
    LevelPct     : REAL;
    HighAlarm    : BOOL;
    LowAlarm     : BOOL;
END_VAR
VAR
END_VAR
BEGIN
    LevelPct := REAL(RawLevel) / 276.48;

    IF LevelPct >= HighAlarmSP THEN
        HighAlarm := TRUE;
    ELSIF LevelPct < HighAlarmSP - Hysteresis THEN
        HighAlarm := FALSE;
    END_IF;

    IF LevelPct <= LowAlarmSP THEN
        LowAlarm := TRUE;
    ELSIF LevelPct > LowAlarmSP + Hysteresis THEN
        LowAlarm := FALSE;
    END_IF;
END_PROGRAM

PROGRAM MotorStarDelta
VAR_INPUT
    Start_btn : BOOL;
    Stop_btn : BOOL;
    Overload : BOOL;
END_VAR
VAR_OUTPUT
    Main_Contactor : BOOL;
    Star_Contactor : BOOL;
    Delta_Contactor : BOOL;
    Fault : BOOL;
END_VAR
VAR
    start_edge : R_TRIG;
    run_request : BOOL;
    timer_star_delta : TON;
END_VAR

start_edge(CLK := Start_btn);

IF Stop_btn OR Overload THEN
    run_request := FALSE;
    timer_star_delta(IN := FALSE, PT := T#3s);
    Main_Contactor := FALSE;
    Star_Contactor := FALSE;
    Delta_Contactor := FALSE;
    Fault := Overload;
ELSIF start_edge.Q THEN
    run_request := TRUE;
END_IF;

IF run_request THEN
    Main_Contactor := TRUE;
    timer_star_delta(IN := TRUE, PT := T#3s);
    IF timer_star_delta.Q THEN
        Star_Contactor := FALSE;
        Delta_Contactor := TRUE;
    ELSE
        Star_Contactor := TRUE;
        Delta_Contactor := FALSE;
    END_IF;
    Fault := FALSE;
ELSE
    Main_Contactor := FALSE;
    Star_Contactor := FALSE;
    Delta_Contactor := FALSE;
    Fault := Overload;
END_IF;
END_PROGRAM

TYPE ConveyorState :
(
    ST_IDLE,
    ST_RUNNING,
    ST_REJECTING,
    ST_FAULT
);
END_TYPE

PROGRAM SortingConveyor
VAR_GLOBAL CONSTANT
    REJECT_DELAY : TIME := T#500MS;
END_VAR
VAR_INPUT
    StartCmd : BOOL;
    SensorPresent : BOOL;
    SensorDefect : BOOL;
    EStop : BOOL;
END_VAR
VAR_OUTPUT
    MotorRun : BOOL;
    RejectSolenoid : BOOL;
END_VAR
VAR
    CurrentState : ConveyorState := ST_IDLE;
    PreviousState : ConveyorState := ST_IDLE;
    RejectTimer : TON;
END_VAR

CASE CurrentState OF
    ST_IDLE:
        IF StartCmd AND NOT EStop THEN
            PreviousState := ST_IDLE;
            CurrentState := ST_RUNNING;
        END_IF;
        MotorRun := FALSE;
        RejectSolenoid := FALSE;

    ST_RUNNING:
        IF EStop THEN
            PreviousState := ST_RUNNING;
            CurrentState := ST_FAULT;
        ELSIF SensorPresent AND SensorDefect THEN
            PreviousState := ST_RUNNING;
            CurrentState := ST_REJECTING;
            RejectTimer(IN := TRUE, PT := REJECT_DELAY);
        END_IF;
        MotorRun := TRUE;
        RejectSolenoid := FALSE;

    ST_REJECTING:
        RejectTimer(IN := TRUE, PT := REJECT_DELAY);
        IF RejectTimer.Q THEN
            PreviousState := ST_REJECTING;
            CurrentState := ST_RUNNING;
            RejectTimer(IN := FALSE);
        END_IF;
        IF EStop THEN
            PreviousState := ST_REJECTING;
            CurrentState := ST_FAULT;
        END_IF;
        MotorRun := FALSE;
        RejectSolenoid := TRUE;

    ST_FAULT:
        MotorRun := FALSE;
        RejectSolenoid := FALSE;
        IF NOT EStop THEN
            CurrentState := PreviousState;
        END_IF;
END_CASE;
END_PROGRAM

FUNCTION_BLOCK PID_Temperature
VAR_INPUT
    Enable : BOOL;
    Setpoint : REAL;
    ProcessValue : REAL;
    Kp : REAL := 2.0;
    Ki : REAL := 0.05;
    Kd : REAL := 0.0;
    CycleTime : TIME := T#100ms;
END_VAR
VAR_OUTPUT
    Output : REAL;
END_VAR
VAR
    Error : REAL;
    PrevError : REAL;
    Integral : REAL;
    Ts : REAL;
END_VAR
BEGIN
    Ts := TIME_TO_REAL(CycleTime);

    IF NOT Enable THEN
        Output := 0.0;
        Integral := 0.0;
        PrevError := 0.0;
    ELSE
        Error := Setpoint - ProcessValue;

        Output := Kp * Error;

        Integral := Integral + Error * Ts;
        Output := Output + Ki * Integral;

        IF Ts > 0.0 THEN
            Output := Output + Kd * (Error - PrevError) / Ts;
        END_IF

        Output := LIMIT(0.0, 100.0, Output);

        PrevError := Error;
    END_IF;
END_FUNCTION_BLOCK

PROGRAM PumpLeadLag
VAR_INPUT
    LevelLow      : BOOL;
    LevelHigh     : BOOL;
    Pump1Fault    : BOOL;
    Pump2Fault    : BOOL;
    ManualMode    : BOOL;
    ManualP1Run   : BOOL;
    ManualP2Run   : BOOL;
END_VAR
VAR_OUTPUT
    P1Run         : BOOL;
    P2Run         : BOOL;
END_VAR
VAR RETAIN
    LeadPump      : INT := 1;
END_VAR

IF ManualMode THEN
    P1Run := ManualP1Run;
    P2Run := ManualP2Run;
ELSE
    IF Pump1Fault THEN
        LeadPump := 2;
    ELSIF Pump2Fault THEN
        LeadPump := 1;
    END_IF;

    IF LevelHigh THEN
        P1Run := FALSE;
        P2Run := FALSE;
    ELSIF LevelLow THEN
        IF LeadPump = 1 THEN
            P1Run := TRUE;
            P2Run := FALSE;
        ELSE
            P1Run := FALSE;
            P2Run := TRUE;
        END_IF;
    ELSE
        P1Run := FALSE;
        P2Run := FALSE;
    END_IF;
END_IF;
END_PROGRAM

PROGRAM BatchDoseSequence
