    CASE currentStep OF
        0:
            SeqActive := FALSE;
            SeqDone := FALSE;
            Valve1 := FALSE;
            Valve2 := FALSE;
            Valve3 := FALSE;
            IF StartSeq THEN
                currentStep := 1;
            END_IF;
        1:
            SeqActive := TRUE;
            SeqDone := FALSE;
            Valve1 := TRUE;
            Valve2 := FALSE;
            Valve3 := FALSE;
            timer1(IN := TRUE, PT := T#2S);
