                currentStep := 2;
                timer1(IN := FALSE);
            END_IF;
        2:
            SeqActive := TRUE;
            SeqDone := FALSE;
            Valve1 := FALSE;
            Valve2 := TRUE;
            Valve3 := FALSE;
            timer2(IN := TRUE, PT := T#3S);
            IF timer2.Q THEN
                currentStep := 3;
                timer2(IN := FALSE);
            END_IF;
        3:
            SeqActive := TRUE;
            SeqDone := FALSE;
            Valve1 := FALSE;
            Valve2 := FALSE;
            Valve3 := TRUE;
            timer3(IN := TRUE, PT := T#1S);
            IF timer3.Q THEN
                currentStep := 4;
                timer3(IN := FALSE);
            END_IF;
        4:
            SeqActive := FALSE;
            SeqDone := TRUE;
            Valve1 := FALSE;
            Valve2 := FALSE;
            Valve3 := FALSE;
            timer1(IN := FALSE);
            timer2(IN := FALSE);
            timer3(IN := FALSE);
    END_CASE;
END_IF;
END_PROGRAM

PROGRAM SafetyInterlock
VAR_INPUT
    EStopOK : BOOL;
    GuardClosed : BOOL;
    ResetPB : BOOL;
END_VAR
VAR_OUTPUT
    MachineEnable : BOOL;
    SafetyFault : BOOL;
END_VAR
VAR
    ResetTrig : R_TRIG;
END_VAR
BEGIN
    ResetTrig(CLK := ResetPB);

    IF (NOT EStopOK OR NOT GuardClosed) THEN
        SafetyFault := TRUE;
    ELSIF (ResetTrig.Q AND EStopOK AND GuardClosed) THEN
        SafetyFault := FALSE;
    END_IF;

    MachineEnable := NOT SafetyFault AND EStopOK AND GuardClosed;
END_PROGRAM

PROGRAM ProductionCounter
VAR_INPUT
    ProductSensor : BOOL;
    ResetBatch : BOOL;
    BatchTarget : INT := 1000;
END_VAR
VAR_OUTPUT
    BatchCount : INT;
    BatchComplete : BOOL;
    TotalCount : INT;
END_VAR
VAR
    sensorEdge : R_TRIG;
    counter : CTU;
END_VAR

sensorEdge(CLK := ProductSensor);
counter(CU := sensorEdge.Q, PV := BatchTarget, R := ResetBatch);

BatchCount := counter.CV;
BatchComplete := counter.Q;

IF sensorEdge.Q THEN
    TotalCount := TotalCount + 1;
END_IF;
END_PROGRAM

FUNCTION_BLOCK MovingAverageFilter
VAR_INPUT
    Enable : BOOL;
    RawInput : REAL;
    WindowSize : INT;
END_VAR
VAR_OUTPUT
    Filtered : REAL;
END_VAR
VAR
    Buffer : ARRAY[0..9] OF REAL;
    Head : INT;
    Count : INT;
    Sum : REAL;
    EffectiveSize : INT;
    i : INT;
END_VAR
BEGIN
    EffectiveSize := WindowSize;
    IF EffectiveSize < 1 THEN
        EffectiveSize := 1;
    END_IF;
    IF EffectiveSize > 10 THEN
        EffectiveSize := 10;
    END_IF;

    IF NOT Enable THEN
        FOR i := 0 TO 9 DO
            Buffer[i] := 0.0;
        END_FOR;
        Head := 0;
        Count := 0;
        Sum := 0.0;
        Filtered := 0.0;
    ELSE
        Buffer[Head] := RawInput;
        IF Count < EffectiveSize THEN
            Count := Count + 1;
            Sum := Sum + RawInput;
        ELSE
            Sum := Sum - Buffer[Head] + RawInput;
        END_IF;
        Head := Head + 1;
        IF Head >= EffectiveSize THEN
            Head := 0;
        END_IF;
        IF Count > 0 THEN
            Filtered := Sum / INT_TO_REAL(Count);
        ELSE
            Filtered := 0.0;
        END_IF;
    END_IF;
END_FUNCTION_BLOCK
